using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly Payments.PaymentGateway _sut = new();

    // ──────────────────────────────────────────────
    //  ChargeAsync
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidCardTokenAndPositiveAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_valid_123";
        var amount = 49.99m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    [DataRow("tok_abc", 100.00)]
    [DataRow("tok_xyz", 0.01)]
    [DataRow("tok_large", 999999.99)]
    public async Task ChargeAsync_VariousValidInputs_ThrowsNotImplementedException(
        string cardToken, double amountDouble)
    {
        // Arrange
        var amount = (decimal)amountDouble;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_NullOrEmptyCardToken_ThrowsNotImplementedException(
        string? cardToken)
    {
        // Arrange
        var amount = 10.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken!, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_zero";
        var amount = 0m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    [DataRow(-1.00)]
    [DataRow(-0.01)]
    [DataRow(-9999.99)]
    public async Task ChargeAsync_NegativeAmount_ThrowsNotImplementedException(
        double amountDouble)
    {
        // Arrange
        var cardToken = "tok_negative";
        var amount = (decimal)amountDouble;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    // ──────────────────────────────────────────────
    //  RefundAsync
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplementedException()
    {
        // Arrange
        var chargeId = "ch_abc123";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    [TestMethod]
    [DataRow("ch_001")]
    [DataRow("ch_long_id_value_xyz")]
    [DataRow("ch_special-chars.ok")]
    public async Task RefundAsync_VariousValidChargeIds_ThrowsNotImplementedException(
        string chargeId)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsNotImplementedException(
        string? chargeId)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId!));
    }
}

